import sys
from kafka import KafkaAdminClient

# Create a KafkaAdminClient object
admin_client = KafkaAdminClient(bootstrap_servers=['localhost:9092'])

# Get the topic names and configuration from command-line arguments
topic_names = [arg.split('=')[1] for arg in sys.argv[1:] if arg.startswith('--topics')]
config = {arg.split('=')[1]: arg.split('=')[2] for arg in sys.argv[1:] if arg.startswith('--config')}

# Create the topics
for topic_name in topic_names:
    admin_client.create_topics(new_topics=[{'topic': topic_name, 'num_partitions': 3, 'replication_factor': 1}])

# Manage partitions
for topic_name in topic_names:
    num_partitions = config[topic_name+'_num_partitions'] if topic_name+'_num_partitions' in config else None
    replication_factor = config[topic_name+'_replication_factor'] if topic_name+'_replication_factor' in config else None
    admin_client.alter_partitions(new_topics=[{'topic': topic_name, 'num_partitions': num_partitions, 'replication_factor': replication_factor}])

# Configure topic settings
for topic_name in topic_names:
    config = {'min.insync.replicas': 2} if 'min.insync.replicas' in config else None
    admin_client.update_topic_config(new_topics=[{'topic': topic_name, 'config': config}])